import { API_URL } from '../../config.js';
import { DbService } from '../../db/db.service.js';
import { refreshIfStale } from './snapshot-refresh.service.js';
import type {
    DbDriver,
    PendingSyncChange,
    SyncPushChange,
    SyncPushFailureResponse,
    SyncPushSuccessResponse,
} from '@motivation/shared';

export type PendingChange = PendingSyncChange;

export type SyncResult =
    | { status: 'idle'; applied: 0 }
    | { status: 'synced'; applied: number }
    | {
        status: 'failed';
        error: string;
        failedAt?: number;
        failedChange?: PendingChange;
    };

type SyncOptions = {
    driver?: DbDriver;
    dbService?: DbService;
    fetchImpl?: typeof fetch;
    /**
     * Story 133 — the tail-pull is now `refreshIfStale`, gated by the cheap
     * `/snapshot/info` check rather than the unconditional binary download.
     * Tests inject a stub to assert the call without going through the
     * full snapshot machinery.
     */
    refreshSnapshot?: typeof refreshIfStale;
};

function resolveDriver(driver?: DbDriver): DbDriver {
    return driver ?? DbService.getInstance().driver;
}

export class SyncService {
    static async listPendingChanges(driver?: DbDriver): Promise<PendingChange[]> {
        console.debug('[SYNC-DEBUG][sync] listPendingChanges() called');
        const db = resolveDriver(driver);
        try {
            const changes = await db.query<PendingChange>(
                `
                    SELECT id, table_name, row_id, operation, row_data, created_at
                    FROM _pending_changes
                    ORDER BY id ASC
                `,
            );
            console.debug('[SYNC-DEBUG][sync] listPendingChanges() returned', changes.length, 'changes');
            return changes;
        } catch (error) {
            if (error instanceof Error && error.message.includes('no such table: _pending_changes')) {
                console.warn('Local DB schema outdated (missing _pending_changes). Auto-wiping OPFS and reloading...', '[SYNC-DEBUG][sync] listPendingChanges() — TABLE MISSING!');
                try {
                    await DbService.getInstance().wipe();
                } catch {
                    // Ignore wipe errors
                }
                window.location.reload();
                // Return empty array to halt execution while reloading
                return [];
            }
            console.error('[SYNC-DEBUG][sync] listPendingChanges() — unexpected error:', error);
            throw error;
        }
    }

    static async getPendingCount(driver?: DbDriver): Promise<number> {
        console.debug('[SYNC-DEBUG][sync] getPendingCount() called');
        const db = resolveDriver(driver);
        try {
            const rows = await db.query<{ count: number }>('SELECT COUNT(*) AS count FROM _pending_changes');
            const count = Number(rows[0]?.count ?? 0);
            console.debug('[SYNC-DEBUG][sync] getPendingCount() =', count);
            return count;
        } catch (error) {
            if (error instanceof Error && error.message.includes('no such table: _pending_changes')) {
                console.warn('Local DB schema outdated (missing _pending_changes). Auto-wiping OPFS and reloading...', '[SYNC-DEBUG][sync] getPendingCount() — TABLE MISSING!');
                try {
                    await DbService.getInstance().wipe();
                } catch {
                    // Ignore wipe errors
                }
                window.location.reload();
                return 0;
            }
            console.error('[SYNC-DEBUG][sync] getPendingCount() — unexpected error:', error);
            throw error;
        }
    }

    static async deletePendingChange(id: number, driver?: DbDriver): Promise<void> {
        const db = resolveDriver(driver);
        await db.execute('DELETE FROM _pending_changes WHERE id = ?', id);
    }

    static async deletePendingChangesFrom(startId: number, driver?: DbDriver): Promise<void> {
        const db = resolveDriver(driver);
        await db.execute('DELETE FROM _pending_changes WHERE id >= ?', startId);
    }

    static async deletePendingChangesUpTo(id: number, driver?: DbDriver): Promise<void> {
        const db = resolveDriver(driver);
        await db.execute('DELETE FROM _pending_changes WHERE id <= ?', id);
    }

    static async syncPendingChanges(options: SyncOptions = {}): Promise<SyncResult> {
        const {
            driver,
            dbService = DbService.getInstance(),
            fetchImpl = fetch,
            refreshSnapshot = refreshIfStale,
        } = options;

        const db = resolveDriver(driver);
        let totalApplied = 0;

        while (true) {
            const pending = await SyncService.listPendingChanges(db);
            if (pending.length === 0) {
                // Story 133 — gate the binary snapshot download behind the
                // cheap /snapshot/info check. The SW also fires `mark-dirty`
                // automatically after the push response, so this call is
                // typically redundant with the trigger-1 path; it exists for
                // the explicit user-driven Sync button (status screen) when
                // pending is already zero, which would otherwise return
                // without ever consulting the server.
                const refreshResult = await refreshSnapshot({ dbService, fetchImpl });

                if (refreshResult.status === 'failed') {
                    if (!navigator.onLine) {
                        console.debug('[SYNC-DEBUG][sync] Snapshot refresh failed offline; treating as success for applied changes.');
                        return totalApplied === 0
                            ? { status: 'idle', applied: 0 }
                            : { status: 'synced', applied: totalApplied };
                    }
                    console.error('[SYNC-DEBUG][sync] Snapshot refresh failed:', refreshResult.error);
                    return {
                        status: 'failed',
                        error: refreshResult.error,
                    };
                }

                // 'fresh' | 'updated' | 'offline' | 'pending' — all acceptable terminal states.
                if (refreshResult.status === 'pending' && refreshResult.pendingCount > 0) {
                    console.debug('[SYNC-DEBUG][sync] Pending changes appeared during refresh; looping to push them.');
                    continue;
                }

                return totalApplied === 0
                     ? { status: 'idle', applied: 0 }
                     : { status: 'synced', applied: totalApplied };
            }

            const changes: SyncPushChange[] = pending.map(({ id: _id, ...change }) => change);

            let response: Response;
            try {
                response = await fetchImpl(`${API_URL}/api/sync/push`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ changes }),
                });
            } catch (error) {
                console.error('[SYNC-DEBUG][sync] Push request FAILED:', error);
                return {
                    status: 'failed',
                    error: error instanceof Error ? error.message : 'Sync request failed',
                };
            }

            console.debug('[SYNC-DEBUG][sync] Push response status:', response.status, response.statusText);

            if (!response.ok) {
                let failure: Partial<SyncPushFailureResponse> = {};
                try {
                    failure = await response.json() as SyncPushFailureResponse;
                } catch {
                    // fall through with default error text below
                }

                const failedAt = typeof failure.failed_at === 'number' ? failure.failed_at : undefined;
                return {
                    status: 'failed',
                    error: failure.error ?? `Sync failed: ${response.status} ${response.statusText}`,
                    failedAt,
                    failedChange: typeof failedAt === 'number' ? pending[failedAt] : undefined,
                };
            }

            const success = await response.json() as SyncPushSuccessResponse;
            const appliedCount = Number(success.applied ?? pending.length);
            totalApplied += appliedCount;

            const lastId = pending[pending.length - 1].id;
            await SyncService.deletePendingChangesUpTo(lastId, db);
        }
    }
}
